func (c *Captcha) Verify(id string, challenge string) (success bool) {
	if challenge == "" || id == "" {
		return
	}

	var chars []byte

	key := c.key(id)
	val, _ := c.store.Get(context2.Background(), key)
	if v, ok := val.([]byte); ok {
		chars = v
	} else {
		return
	}

	defer func() {

		c.store.Delete(context2.Background(), key)
	}()

	if len(chars) != len(challenge) {
		return
	}

	for i, c := range chars {
		if c != challenge[i]-48 {
			return
		}
	}

	return true
}
